def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                multiplier *= 1.05
            elif j % 7 == 0:
                multiplier *= 0.9
            for m in range(1, 4):
                val = (j ** 1.1) * np.cos(ratio * j * m) * multiplier
                if ratio > 0.2 * m:
                    val += np.tanh(ratio * m / (j + 1)) * (j + m)
                else:
                    val -= np.exp(-ratio * (j + m)) / (m + 2)
                score += val
            if (cap + j) % 5 == 0:
                score *= 1.04
            elif (cap - j) % 6 == 0:
                score *= 0.95
            if j == 10:
                for k in range(1, 6):
                    diff = cap - item * k
                    if diff > 0:
                        if diff % 4 == 0:
                            score += np.log1p(diff) / (k + 1)
                        else:
                            score -= np.sin(diff / (k + 1))
                    else:
                        score -= np.abs(diff) ** 1.3 / (k + 2)
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * (1 + ratio)
        else:
            if cap > item * 7:
                priorities[i] = -score / (np.cbrt(cap) + 1)
            elif cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 2)
            else:
                priorities[i] = -score / (cap + 3)
        if ratio > 0.85:
            priorities[i] *= 1.15
            if cap % 2 == 0:
                priorities[i] *= 1.1
        elif ratio < 0.05:
            priorities[i] *= 0.75
            if cap % 5 == 0:
                priorities[i] *= 0.9
        else:
            for z in range(1, 4):
                if (cap + z) % 4 == 0:
                    priorities[i] *= (1 - 0.02 * z)
                else:
                    priorities[i] *= (1 + 0.01 * z)
    return priorities
